void adaptive_sort(std::vector<int>& arr) {
    // Array of size 0 or 1 is already sorted by definition
    if (arr.size() < 2) return;

    // O(N) check - instantly breaks early to O(1) on randomized data
    if (std::is_sorted(arr.begin(), arr.end())) {
        return;
    }

    // O(N) check - captures worst-case scenarios and resolves in O(N)
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
        return;
    }

    // Fallback to highly-optimized introsort for random/unpredictable distributions
    std::sort(arr.begin(), arr.end());
}

